def search_norm_contains(term):
    nterm = normalize_arabic(term)
    res = []
    for h in hadith_data:
        for field in ('Matn','hadithTxt'):
            txt = h.get(field) or ""
            n = normalize_arabic(txt)
            if nterm in n:
                res.append((h, field))
                break
    return res

